import{_ as t,o as r,c as s,ag as a}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"User Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/user-management.md","filePath":"guide/user-management.md"}'),i={name:"guide/user-management.md"};function n(o,e,l,d,c,g){return r(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h1><p>GeniusHRM separates <strong>Users</strong> (login accounts) from <strong>Employees</strong> (HR records). A user account grants access to the system; an employee record stores HR data. The two are linked, but can exist independently.</p><hr><h2 id="accessing-user-management" tabindex="-1">Accessing User Management <a class="header-anchor" href="#accessing-user-management" aria-label="Permalink to &quot;Accessing User Management&quot;">​</a></h2><p>Navigate to <strong>Admin Panel → Users</strong> or go to <code>/admin/users</code>. This section is only visible to users with the <strong>Admin</strong> role.</p><hr><h2 id="creating-a-user" tabindex="-1">Creating a User <a class="header-anchor" href="#creating-a-user" aria-label="Permalink to &quot;Creating a User&quot;">​</a></h2><ol><li>Click <strong>Add User</strong> (top right)</li><li>Fill in the required fields:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Yes</td><td>Full display name</td></tr><tr><td><strong>Email</strong></td><td>Yes</td><td>Must be unique; used as login identifier</td></tr><tr><td><strong>Password</strong></td><td>Yes</td><td>Minimum 8 characters</td></tr><tr><td><strong>Role</strong></td><td>Yes</td><td>Select from available roles</td></tr><tr><td><strong>Employee</strong></td><td>No</td><td>Link to an existing employee record</td></tr><tr><td><strong>Status</strong></td><td>Yes</td><td><code>Active</code> or <code>Inactive</code></td></tr></tbody></table><ol start="3"><li>Click <strong>Create User</strong></li></ol><p>The user receives a welcome email (if SMTP is configured) with a link to set their password.</p><div class="tip custom-block"><p class="custom-block-title">Linking to an Employee</p><p>When a user account is linked to an employee record, the employee&#39;s profile information (name, department, position) is automatically reflected in their user account. This ensures consistency across HR records and login sessions.</p></div><hr><h2 id="editing-a-user" tabindex="-1">Editing a User <a class="header-anchor" href="#editing-a-user" aria-label="Permalink to &quot;Editing a User&quot;">​</a></h2><ol><li>Find the user in the list using the search bar or filters</li><li>Click the <strong>Edit</strong> icon (pencil) in the Actions column</li><li>Modify any field except the password (use the password reset function for that)</li><li>Click <strong>Update User</strong></li></ol><hr><h2 id="resetting-a-password" tabindex="-1">Resetting a Password <a class="header-anchor" href="#resetting-a-password" aria-label="Permalink to &quot;Resetting a Password&quot;">​</a></h2><h3 id="admin-reset" tabindex="-1">Admin Reset <a class="header-anchor" href="#admin-reset" aria-label="Permalink to &quot;Admin Reset&quot;">​</a></h3><ol><li>Locate the user in the Users list</li><li>Click the <strong>More</strong> (ellipsis) menu → <strong>Reset Password</strong></li><li>Enter a new password and confirm</li><li>Click <strong>Reset</strong> — the user can log in immediately with the new password</li></ol><h3 id="user-self-reset" tabindex="-1">User Self-Reset <a class="header-anchor" href="#user-self-reset" aria-label="Permalink to &quot;User Self-Reset&quot;">​</a></h3><p>Users can reset their own password via the login page:</p><ol><li>Click <strong>Forgot Password</strong> on the login screen</li><li>Enter their registered email address</li><li>A password reset link is emailed to them (requires SMTP to be configured)</li><li>They click the link and set a new password</li></ol><hr><h2 id="deactivating-a-user" tabindex="-1">Deactivating a User <a class="header-anchor" href="#deactivating-a-user" aria-label="Permalink to &quot;Deactivating a User&quot;">​</a></h2><p>Deactivating a user prevents them from logging in without deleting their account or any associated data.</p><ol><li>Open the user&#39;s edit form</li><li>Change <strong>Status</strong> to <code>Inactive</code></li><li>Click <strong>Update User</strong></li></ol><p>The user will be logged out of any active sessions immediately.</p><p>To reactivate, repeat the process and set <strong>Status</strong> back to <code>Active</code>.</p><hr><h2 id="deleting-a-user" tabindex="-1">Deleting a User <a class="header-anchor" href="#deleting-a-user" aria-label="Permalink to &quot;Deleting a User&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a user is irreversible. Their login account is permanently removed. Any linked employee record remains intact.</p></div><ol><li>Click the <strong>More</strong> (ellipsis) menu → <strong>Delete User</strong></li><li>Confirm the deletion in the confirmation dialog</li></ol><hr><h2 id="filtering-and-searching-users" tabindex="-1">Filtering and Searching Users <a class="header-anchor" href="#filtering-and-searching-users" aria-label="Permalink to &quot;Filtering and Searching Users&quot;">​</a></h2><p>The user list supports the following filters:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Options</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>By name or email</td></tr><tr><td><strong>Role</strong></td><td>Filter by any assigned role</td></tr><tr><td><strong>Status</strong></td><td>Active / Inactive</td></tr></tbody></table><p>Results are paginated with 15 users per page by default.</p><hr><h2 id="user-audit-trail" tabindex="-1">User Audit Trail <a class="header-anchor" href="#user-audit-trail" aria-label="Permalink to &quot;User Audit Trail&quot;">​</a></h2><p>Every action a user takes (create, update, delete operations across all modules) is recorded in the <strong>Audit Log</strong>. See <a href="/guide/audit-log.html">Audit Log</a> for details.</p><hr><h2 id="bulk-operations" tabindex="-1">Bulk Operations <a class="header-anchor" href="#bulk-operations" aria-label="Permalink to &quot;Bulk Operations&quot;">​</a></h2><p>From the Users list, you can select multiple users and:</p><ul><li><strong>Deactivate selected</strong> — Set all selected users to Inactive</li><li><strong>Activate selected</strong> — Set all selected users to Active</li><li><strong>Delete selected</strong> — Permanently remove selected users (use with caution)</li></ul><p>Select users using the checkbox in each row, then use the <strong>Bulk Actions</strong> dropdown.</p>',45)])])}const m=t(i,[["render",n]]);export{u as __pageData,m as default};
